import React from 'react';

export interface TabItem {
  title: string;
  icon: React.ReactNode;
  content: React.ReactNode;
}

export interface TabSwitcherProps {
  tabItems: TabItem[];
}

TabSwitcher.css:
.tab-switcher-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 100%;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.content-area {
  width: 100%;
  min-height: 200px;
  margin-bottom: 20px;
  animation: fadeIn 0.3s ease-in-out;
}

.tabs-list {
  display: flex;
  justify-content: center;
  gap: 30px;
  padding: 20px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 16px;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.tab-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  cursor: pointer;
  transition: all 0.3s ease;
  opacity: 0.6;
}

.tab-item.active {
  opacity: 1;
}

.tab-icon {
  font-size: 24px;
  margin-bottom: 8px;
  transition: all 0.3s ease;
  color: #888;
}

.tab-item.active .tab-icon {
  font-size: 32px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.tab-title {
  font-size: 14px;
  font-weight: 500;
  color: #aaa;
  transition: all 0.3s ease;
}

.tab-item.active .tab-title {
  font-size: 16px;
  font-weight: 700;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

TabSwitcher.tsx:
import React, { useState } from 'react';
import { TabSwitcherProps } from './types';
import './TabSwitcher.css';

/**
 * TabSwitcher Component
 * 
 * Features:
 * - Modern gradient style
 * - Content displayed above tabs (Requirement 10)
 * - Active state changes color, size for both icon and title
 * - Accessible keyboard navigation
 */
export const TabSwitcher: React.FC<TabSwitcherProps> = ({ tabItems }) => {
  // Default first tab is active (Requirement 1)
  const [activeIndex, setActiveIndex] = useState<number>(0);

  if (!tabItems || tabItems.length === 0) {
    return null;
  }

  const handleTabClick = (index: number) => {
    setActiveIndex(index);
  };

  return (
    <div className="tab-switcher-container">
      {/* Content located above tab configuration (Requirement 10) */}
      <div className="content-area">
        {tabItems[activeIndex].content}
      </div>

      {/* Tab Configuration */}
      <div className="tabs-list">
        {tabItems.map((item, index) => (
          <div
            key={index}
            className={`tab-item ${index === activeIndex ? 'active' : ''}`}
            onClick={() => handleTabClick(index)}
            role="tab"
            aria-selected={index === activeIndex}
            tabIndex={0}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                handleTabClick(index);
              }
            }}
          >
            {/* Icon above title (Requirement 3) */}
            <div className="tab-icon">{item.icon}</div>
            {/* Title below icon (Requirement 4) */}
            <div className="tab-title">{item.title}</div>
          </div>
        ))}
      </div>
    </div>
  );
};
